#!/usr/bin/env node
// scaffold-day7.mjs - Apply Day 7 changes to the headcount repo.
// Run from the repo root: node scaffold-day7.mjs
//
// Day 7 = Workforce expansion: 4 new C-suite execs, 104 dormant specialists,
// 12 departments, ritual filter updates, dashboard sidebar overhaul.
//
// IMPORTANT:
//   - This OVERWRITES files. Commit your current state first.
//   - It does NOT run the database migration. You must run
//     supabase/migrations/0010_day7.sql in your Supabase SQL editor
//     manually after this scaffold completes.
//   - It does NOT run the seeds. After applying, run:
//     pnpm tsx apps/orchestrator/src/seed/day7-org-restructure.ts
//     pnpm tsx apps/orchestrator/src/seed/day7-bulk-specialists.ts

import { mkdirSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";

const ROOT = process.cwd();

function writeFile(relPath, b64) {
  const full = resolve(ROOT, relPath);
  mkdirSync(dirname(full), { recursive: true });
  const buf = Buffer.from(b64, "base64");
  writeFileSync(full, buf);
  console.log(`  + ${relPath} (${buf.length} bytes)`);
}

console.log("");
console.log("Applying Day 7 to: " + ROOT);
console.log("");

writeFile('apps/dashboard/app/api/agents/by-department/route.ts', '');
writeFile('apps/dashboard/app/page.tsx', '');
writeFile('apps/orchestrator/src/rituals/chatter.ts', '');
writeFile('apps/orchestrator/src/rituals/reflection.ts', '');
writeFile('apps/orchestrator/src/rituals/standup.ts', '');
writeFile('apps/orchestrator/src/seed/agency-agents-catalog.ts', '');
writeFile('apps/orchestrator/src/seed/day7-bulk-specialists.ts', '');
writeFile('apps/orchestrator/src/seed/day7-org-restructure.ts', '');
writeFile('apps/orchestrator/src/seed/singaporean-names.ts', '');
writeFile('packages/shared/src/schema.ts', '');
writeFile('supabase/migrations/0010_day7.sql', '');

console.log("");
console.log("Done. Wrote 11 files (184676 bytes total).");
console.log("");
console.log("Next steps:");
console.log("  1. Run supabase/migrations/0010_day7.sql in the Supabase SQL editor");
console.log("  2. pnpm install   (no new deps but workspace needs to refresh)");
console.log("  3. pnpm tsx apps/orchestrator/src/seed/day7-org-restructure.ts");
console.log("  4. pnpm tsx apps/orchestrator/src/seed/day7-bulk-specialists.ts");
console.log("  5. Restart the orchestrator and dashboard");
console.log("");
